    this.SetDirty();
  }

  private void ReloadProfilePreview()
  {
    if (this.Profile == null || !this._entManager.EntityExists(this.PreviewDummy))
      return;
    HumanoidAppearanceComponent humanoid;
    if (this._entManager.TryGetComponent<HumanoidAppearanceComponent>(this.PreviewDummy, ref humanoid))
    {
      Dictionary<HumanoidVisualLayers, SlotFlags> hiddenLayers = humanoid.HiddenLayers;
      HumanoidAppearanceSystem appearanceSystem = this._entManager.System<HumanoidAppearanceSystem>();
      appearanceSystem.LoadProfile(this.PreviewDummy, this.Profile, humanoid);
      appearanceSystem.SetLayersVisibility(Entity<HumanoidAppearanceComponent>.op_Implicit((this.PreviewDummy, humanoid)), (IEnumerable<HumanoidVisualLayers>) hiddenLayers.Keys, false);
    }
    this.SetDirty();
  }

  private void SetPreviewRotation(Direction direction)
  {
    this.SpriteView.OverrideDirection = new Direction?((Direction) (int) (sbyte) (direction % 4 * 2));
  }

  private void SetDirty()
  {
    if (this.Profile != null)
    {
      PlayerPreferences preferences = this._preferencesManager.Preferences;
      if ((preferences != null ? (preferences.SelectedCharacter.MemberwiseEquals((ICharacterProfile) this.Profile) ? 1 : 0) : 0) == 0)
      {
        this.IsDirty = true;
        return;
      }
    }
    this.IsDirty = false;
  }

