  private void SetName(string newName)
  {
    this.Profile = this.Profile?.WithName(newName);
    this.IsDirty = true;
    this._entManager.System<MetaDataSystem>().SetEntityName(this.PreviewDummy, newName, (MetaDataComponent) null, true);
  }

  private void SetAge(int newAge)
  {
    this.Profile = this.Profile?.WithAge(newAge);
    this.ReloadPreview();
  }

  private void SetSex(Sex newSex)
  {
    this.Profile = this.Profile?.WithSex(newSex);
    switch (newSex)
    {
      case Sex.Male:
        this.Profile = this.Profile?.WithGender((Gender) 3);
        break;
      case Sex.Female:
        this.Profile = this.Profile?.WithGender((Gender) 2);
        break;
      default:
        this.Profile = this.Profile?.WithGender((Gender) 1);
        break;
    }
    this.UpdateGenderControls();
    this.UpdateTTSVoicesControls();
    this.Markings.SetSex(newSex);
    this.ReloadProfilePreview();
  }

  private void SetGender(Gender newGender)
  {
    this.Profile = this.Profile?.WithGender(newGender);
    this.ReloadPreview();
  }

  private void UpdateNameEdit() => this.NameEdit.Text = this.Profile?.Name ?? "";

  private void UpdateAgeEdit() => this.AgeEdit.Text = this.Profile?.Age.ToString() ?? "";

  private void UpdateSexControls()
  {
    if (this.Profile == null)
      return;
    SpeciesPrototype speciesPrototype = this._currentSpecies ?? this._humanSpecies;
    this.SexButton.Clear();
    foreach (Sex sex in speciesPrototype.Sexes)
      this.SexButton.AddItem(Loc.GetString($"humanoid-profile-editor-sex-{sex.ToString().ToLower()}-text"), new int?((int) sex));
    if (speciesPrototype.Sexes.Contains(this.Profile.Sex))
      this.SexButton.SelectId((int) this.Profile.Sex);
    else
      this.SexButton.SelectId((int) speciesPrototype.Sexes[0]);
  }

  private void UpdateGenderControls()
  {
    if (this.Profile == null)
      return;
    this.PronounsButton.SelectId((int) this.Profile.Gender);
  }

  private void UpdateSkinColor()
  {
    if (this.Profile == null)
      return;
    ((Range) this.Skin).Value = SkinColor.HumanSkinToneFromColor(this.Profile.Appearance.SkinColor);
  }

  private void UpdateMarkings()
  {
    if (this.Profile == null)
      return;
    this.Markings.SetData(this.Profile.Appearance.Markings, ProtoId<SpeciesPrototype>.op_Implicit(this.Profile.Species), this.Profile.Sex, this.Profile.Appearance.SkinColor, this.Profile.Appearance.EyeColor);
    this.ApplyTraitLocks();
  }

  private void OnTraitItemsReceived(HashSet<string> unlockedItems)
  {
    this._unlockedTraitItems = unlockedItems;
    this.ApplyTraitLocks();
  }

  private void ApplyTraitLocks()
  {
    HashSet<string> blockedMarkings = new HashSet<string>();
    foreach (EntityPrototype enumeratePrototype in this._prototypeManager.EnumeratePrototypes<EntityPrototype>())
    {
      PubgMarkingItemComponent markingItemComponent;
      if (enumeratePrototype.TryGetComponent<PubgMarkingItemComponent>(ref markingItemComponent, this._compFactory) && !this._unlockedTraitItems.Contains(enumeratePrototype.ID))
        blockedMarkings.Add(markingItemComponent.MarkingId);
    }
    if (!this.HasFelinidPermission())
    {
      foreach (string felinidBaseMarking in PubgHumanoidProfileEditor.FelinidBaseMarkings)
        blockedMarkings.Add(felinidBaseMarking);
    }
    this.Markings.SetBlockedMarkings((IEnumerable<string>) blockedMarkings);
  }

  private void UpdateHairPickers()
  {
    if (this.Profile == null)
      return;
    List<Marking> markingList1;
    if (!ProtoId<MarkingPrototype>.op_Equality(ProtoId<MarkingPrototype>.op_Implicit(this.Profile.Appearance.HairStyleId), HairStyles.DefaultHairStyle))
      markingList1 = new List<Marking>()
