    List<Marking> markings1 = markingList1;
    List<Marking> markingList2;
    if (!ProtoId<MarkingPrototype>.op_Equality(ProtoId<MarkingPrototype>.op_Implicit(this.Profile.Appearance.FacialHairStyleId), HairStyles.DefaultFacialHairStyle))
      markingList2 = new List<Marking>()
