        {
          this.Profile.Appearance.FacialHairColor
        })
      };
    else
      markingList2 = new List<Marking>();
    List<Marking> markings2 = markingList2;
    this.HairStylePicker.UpdateData(markings1, ProtoId<SpeciesPrototype>.op_Implicit(this.Profile.Species), 1);
    this.FacialHairPicker.UpdateData(markings2, ProtoId<SpeciesPrototype>.op_Implicit(this.Profile.Species), 1);
  }

