  private void RandomizeProfile()
  {
    HashSet<string> ignoredSpecies;
    if (!this.HasFelinidPermission())
      ignoredSpecies = new HashSet<string>() { "Felinid" };
    else
      ignoredSpecies = (HashSet<string>) null;
    HumanoidCharacterProfile characterProfile = HumanoidCharacterProfile.Random(ignoredSpecies);
    if (ProtoId<SpeciesPrototype>.op_Inequality(characterProfile.Species, ProtoId<SpeciesPrototype>.op_Implicit("Human")) && ProtoId<SpeciesPrototype>.op_Inequality(characterProfile.Species, ProtoId<SpeciesPrototype>.op_Implicit("Felinid")))
      characterProfile = characterProfile.WithSpecies("Human");
    this.Profile = characterProfile;
    this.SetProfile(this.Profile, this.CharacterSlot);
    this.SetDirty();
  }

  private void RandomizeName()
  {
    if (this.Profile == null)
      return;
    this.SetName(HumanoidCharacterProfile.GetName(ProtoId<SpeciesPrototype>.op_Implicit(this.Profile.Species), this.Profile.Gender));
    this.UpdateNameEdit();
  }

  protected virtual void ExitedTree()
  {
    ((Control) this).ExitedTree();
    LobbyTraitItemsSystem traitItemsSystem;
    if (this._entManager.EntitySysManager.TryGetEntitySystem<LobbyTraitItemsSystem>(ref traitItemsSystem))
      traitItemsSystem.OnTraitItemsReceived -= new Action<HashSet<string>>(this.OnTraitItemsReceived);
    if (this._entManager.EntityExists(this.PreviewDummy))
      this._entManager.DeleteEntity(new EntityUid?(this.PreviewDummy));
    this.PreviewDummy = EntityUid.Invalid;
  }

